+        // If target is occupied, evict the occupant to the dragged window's
+        // old position (swap) or best-fit
+        if (!grid.isAreaFree(clampedCol, clampedRow, span.cols, span.rows)) {
+            const occupantId = grid.windowAtCell(clampedCol, clampedRow);
+            if (occupantId) {
+                const occupant = this._windowForId(occupantId);
+                const occupantAlloc = grid.getWindow(occupantId);
+                grid.removeWindow(occupantId);
+
+                if (occupant && occupantAlloc) {
+                    // Try to place occupant at the dragged window's old position
+                    let placed = false;
+                    if (oldAlloc)
+                        placed = grid.placeWindowAt(occupantId, oldAlloc.col, oldAlloc.row,
+                            occupantAlloc.spanCols, occupantAlloc.spanRows);
+                    if (!placed)
+                        grid.placeWindow(occupantId, occupantAlloc.spanCols, occupantAlloc.spanRows);
+
+                    const newAlloc = grid.getWindow(occupantId);
+                    if (newAlloc) {
+                        const occRect = grid.cellToPixels(newAlloc.col, newAlloc.row,
+                            newAlloc.spanCols, newAlloc.spanRows);
+                        const geo = global.workspace_manager.get_active_workspace().get_work_area_for_monitor(monitorIndex);
+                        occupant.move_resize_frame(true,
+                            geo.x + occRect.x, geo.y + occRect.y,
+                            occRect.width, occRect.height);
+                    }
+                }
+            }
+        }
+
